-- Product catalog initial data generated from the provided 11 UTF-8 product txt files.
-- Parsed 2891 source rows; skipped 10 duplicate machine rows; generated 2881 product rows.
-- Source documents do not include gpu_power_tops or token output, so those values are initialized as NULL and 0.
-- rent_price is populated from the first hourly price shown in the source documents.
SET NAMES utf8mb4;

ON DUPLICATE KEY UPDATE `region_name` = VALUES(`region_name`), `sort_no` = VALUES(`sort_no`), `status` = VALUES(`status`);

ON DUPLICATE KEY UPDATE `model_code` = VALUES(`model_code`), `model_name` = VALUES(`model_name`), `sort_no` = VALUES(`sort_no`), `status` = VALUES(`status`);

ON DUPLICATE KEY UPDATE `product_name` = VALUES(`product_name`), `machine_code` = VALUES(`machine_code`), `machine_alias` = VALUES(`machine_alias`), `region_id` = VALUES(`region_id`), `gpu_model_id` = VALUES(`gpu_model_id`), `gpu_memory_gb` = VALUES(`gpu_memory_gb`), `gpu_power_tops` = VALUES(`gpu_power_tops`), `rent_price` = VALUES(`rent_price`), `token_output_per_minute` = VALUES(`token_output_per_minute`), `token_output_per_day` = VALUES(`token_output_per_day`), `rentable_until` = VALUES(`rentable_until`), `total_stock` = VALUES(`total_stock`), `available_stock` = VALUES(`available_stock`), `rented_stock` = VALUES(`rented_stock`), `cpu_model` = VALUES(`cpu_model`), `cpu_cores` = VALUES(`cpu_cores`), `memory_gb` = VALUES(`memory_gb`), `system_disk_gb` = VALUES(`system_disk_gb`), `data_disk_gb` = VALUES(`data_disk_gb`), `max_expand_disk_gb` = VALUES(`max_expand_disk_gb`), `driver_version` = VALUES(`driver_version`), `cuda_version` = VALUES(`cuda_version`), `has_cache_optimization` = VALUES(`has_cache_optimization`), `status` = VALUES(`status`), `sort_no` = VALUES(`sort_no`), `version_no` = VALUES(`version_no`);
